class Solution:
    def findItinerary(self, tickets: List[List[str]]) -> List[str]:
        graph = defaultdict(list)
        for a, b in tickets:
            graph[a].append(b)
        for k in graph:
            graph[k].sort(reverse=True)
        route = []
        def dfs(u):
            while graph[u]:
                dfs(graph[u].pop())
            route.append(u)
        dfs('JFK')
        return route[::-1]

