class Solution {
    unordered_map<string, vector<string>> g;
    vector<string> route;
    void dfs(string u) {
        auto& v = g[u];
        while (!v.empty()) {
            string nxt = v.back(); v.pop_back();
            dfs(nxt);
        }
        route.push_back(u);
    }
public:
    vector<string> findItinerary(vector<vector<string>>& tickets) {
        for (auto& t : tickets) g[t[0]].push_back(t[1]);
        for (auto& p : g) sort(p.second.begin(), p.second.end(), greater<string>());
        dfs("JFK");
        reverse(route.begin(), route.end());
        return route;
    }
};

